import{_ as n,C as o,o as l,c as s,E as a,w as t,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Slovakia Legal Rights","description":"Legal rights for transgender people in Slovakia","frontmatter":{"layout":"doc","title":"Slovakia Legal Rights","description":"Legal rights for transgender people in Slovakia"},"headers":[],"relativePath":"europe/slovakia/legal-rights.md","filePath":"europe/slovakia/legal-rights.md","lastUpdated":null}'),g={name:"europe/slovakia/legal-rights.md"};function c(h,e,u,m,p,f){const i=o("Badge");return l(),s("div",null,[a(i,{variant:"red"},{default:t(()=>[...e[0]||(e[0]=[r("Sterilization Required",-1)])]),_:1}),a(i,{variant:"yellow"},{default:t(()=>[...e[1]||(e[1]=[r("Court-Approved Process",-1)])]),_:1}),a(i,{variant:"yellow"},{default:t(()=>[...e[2]||(e[2]=[r("Limited Anti-Discrimination",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="legal-rights-in-slovakia" tabindex="-1">Legal Rights in Slovakia <a class="header-anchor" href="#legal-rights-in-slovakia" aria-label="Permalink to &quot;Legal Rights in Slovakia&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Slovakia has one of the <strong>most restrictive gender recognition systems</strong> in the EU, requiring sterilization:</p><ul><li><strong>Requirements</strong>: Psychiatric diagnosis + HRT + sterilization (sex reassignment surgery)</li><li><strong>Process</strong>: File a court application with medical certification</li><li><strong>Sterilization</strong>: Effectively mandatory — the law refers to &quot;sex reassignment surgery&quot; which is interpreted as requiring sterilization</li><li><strong>Age</strong>: 18+ only</li><li><strong>Marriage</strong>: Married individuals face additional hurdles</li></ul><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li>Diagnosis from a psychiatrist or sexuologist (Bratislava only)</li><li>Minimum 1-2 years of documented HRT and real-life experience</li><li>Sex reassignment surgery (sterilization)</li><li>File a court application for gender marker change</li><li>Court decision and civil registry update</li></ol><p><strong>Note</strong>: The sterilization requirement has been condemned by human rights organizations including the European Parliament and the UN. The European Court of Human Rights has found Slovakia in violation of Article 8 (right to private life). Despite this, the law has not been changed.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Processed through the <strong>Civil Registry</strong> (Matrika)</li><li>Can be done separately from gender marker change</li><li>Requires a valid reason</li><li>Processed within 30-60 days</li><li>Name change without gender marker change is possible</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: Prohibited under the Labour Code</li><li><strong>Goods and Services</strong>: Protected under the Anti-Discrimination Act</li><li><strong>Education</strong>: General protections apply</li><li><strong>Gender identity</strong>: Not explicitly listed in anti-discrimination law but covered by interpretation in some cases</li></ul><p>The <strong>Anti-Discrimination Act</strong> (Antidiskriminačný zákon) prohibits discrimination based on sexual orientation, but gender identity is not explicitly mentioned. The Slovak National Centre for Human Rights handles complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> includes hate crime provisions</li><li>Sexual orientation is a protected characteristic</li><li>Gender identity is <strong>not explicitly mentioned</strong></li><li>Enforcement is limited — police training on LGBTQ+ issues is minimal</li><li>Far-right groups are active in some regions</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards recognized internationally</li><li>Previous documents are archived</li><li>The sterilization requirement means only those who undergo surgery can access updated documents</li><li>People who cannot or will not undergo sterilization cannot change their legal gender</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.inakost.sk/" target="_blank" rel="noreferrer">Iniciatíva Inakosť (LGBTQ+ Organization)</a></li><li><a href="https://www.snslp.sk/" target="_blank" rel="noreferrer">Slovak National Centre for Human Rights</a></li><li><a href="https://www.ilga-europe.org/country/slovakia/" target="_blank" rel="noreferrer">ILGA-Europe - Slovakia</a></li><li><a href="https://www.protiprudu.sk/" target="_blank" rel="noreferrer">Proti Prúdu (Trans Organization)</a></li></ul>',18))])}const w=n(g,[["render",c]]);export{v as __pageData,w as default};
